mapper.select:
select job_id, user_id, thread_id, message_id, extractor_version, status, attempt_count, last_error,
       eligible_turn_count, created_at, updated_at, started_at, completed_at
from memory_extraction_jobs
where user_id = #{userId}
  and thread_id = #{threadId}
  and extractor_version = #{extractorVersion}
  and status = 'SUCCEEDED'
order by completed_at desc nulls last, updated_at desc
limit 1

select count(1)
from memory_extraction_jobs
where user_id = #{userId}
  and thread_id = #{threadId}
  and extractor_version = #{extractorVersion}
  and status in ('QUEUED', 'RUNNING')

mapper.update:
update memory_extraction_jobs
set status = #{status}, started_at = #{updatedAt}, updated_at = #{updatedAt}
where job_id = #{jobId} and status = #{expectedStatus}

update memory_extraction_jobs
set status = #{status}, last_error = null, updated_at = #{updatedAt}, completed_at = #{updatedAt}
where job_id = #{jobId}
